export const 鎮宅牛馬 = (bi) => {
    const u = bi.u, k = 2.7;
    const X = (c) => (c - 3.95) * k;
    const Z = (r) => (r - 0.7) * k + 2;
    const 線 = (書, 寬 = 0.38) => bi.一筆({ 寬: 寬 * u, 起: '藏', 收: '回' }, 書);
    const 圈 = (x, z, r = 0.28) => {
        const c = bi.ctx;
        c.save();
        c.lineWidth = 0.3 * u;
        bi.A(X(x), Z(z), r * k);
        c.restore();
    };
    const 桿 = (x0, x1, z) => {
        線(p => p.M(X(x0) + 0.32 * k, Z(z)).L(X(x1) - 0.32 * k, Z(z)));
        圈(x0, z);
        圈(x1, z);
    };
    // 符頭：桿二＋斜圈鏈二＋側圈
    桿(0.3, 7.4, 1.0);
    桿(0.3, 7.2, 2.35);
    線(p => p.M(X(3.02), Z(3.69)).L(X(4.98), Z(4.11)));
    圈(2.6, 3.6);
    圈(5.4, 4.2);
    線(p => p.M(X(3.12), Z(5.40)).L(X(4.78), Z(5.79)));
    圈(2.7, 5.3);
    圈(5.2, 5.9);
    圈(0.4, 3.6);
    圈(7.2, 3.5);
    圈(0.4, 6.1);
    圈(7.3, 6.0);
    // 頂匣桁（寬箱內桁）
    線(p => p.M(X(0.6), Z(6.9)).L(X(0.6), Z(9.2)).L(X(7.3), Z(9.1))
        .L(X(7.3), Z(6.8)).L(X(0.55), Z(6.9)), 0.42);
    線(p => p.M(X(0.7), Z(8.0)).L(X(7.2), Z(7.9)));
    // 左目梯（四箱）
    線(p => p.M(X(0.7), Z(9.6)).L(X(0.7), Z(16.0)));
    線(p => p.M(X(3.3), Z(9.55)).L(X(3.3), Z(15.95)));
    for (let i = 0; i <= 4; i++)
        線(p => p.M(X(0.7), Z(9.6 + i * 1.6)).L(X(3.3), Z(9.55 + i * 1.6)));
    // 右呂箱承巛曲柱
    線(p => p.M(X(4.2), Z(9.6)).L(X(4.2), Z(12.9)));
    線(p => p.M(X(6.6), Z(9.55)).L(X(6.6), Z(12.85)));
    for (const z of [9.6, 11.2, 12.85])
        線(p => p.M(X(4.2), Z(z)).L(X(6.6), Z(z - 0.05)));
    // 巛曲柱（雙波豎）
    線(p => p.M(X(4.6), Z(13.3))
        .C(X(4.2), Z(14.1), X(4.9), Z(14.8), X(4.5), Z(15.6))
        .C(X(4.2), Z(16.2), X(4.8), Z(16.8), X(4.5), Z(17.4)));
    線(p => p.M(X(6.1), Z(13.3))
        .C(X(5.7), Z(14.1), X(6.4), Z(14.8), X(6.0), Z(15.6))
        .C(X(5.7), Z(16.2), X(6.3), Z(16.8), X(6.0), Z(17.4)));
    // 迴脚
    線(p => p.M(X(0.8), Z(16.4)).C(X(0.6), Z(17.3), X(0.5), Z(18.0), X(0.5), Z(18.6)));
    線(p => p.M(X(3.2), Z(16.4)).C(X(3.3), Z(17.2), X(3.3), Z(17.9), X(3.2), Z(18.5)));
};
